-- Заклинания SRD 5.1
INSERT INTO spells (name, level, school, casting_time, range, components, duration, concentration, ritual, description, higher_levels, classes, is_homebrew) VALUES

-- ЗАГОВОРЫ (0)
('Волшебная рука', 0, 'conjuration', '1 действие', '30 фт', '{"v":true,"s":true,"m":null}', '1 минута', false, false, 'Призрачная рука появляется в точке на ваш выбор в пределах 30 фт. Рука существует на время действия или пока вы не отпустите её. Вы можете использовать её для манипуляции предметами, открытия дверей, поднятия до 10 фунтов, переноса предметов.', NULL, '["bard","sorcerer","warlock","wizard","artificer"]', false),

('Священное пламя', 0, 'evocation', '1 действие', '60 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Пламя нисходит на существо в пределах 60 фт. Цель должна пройти спасбросок Ловкости СЛ Вашей магии или получить 1d8 урона сиянием. Укрытие не даёт бонус к спасброску.', 'Урон увеличивается на 1d8 на 5, 11 и 17 уровнях.', '["cleric"]', false),

('Огненный снаряд', 0, 'evocation', '1 действие', '120 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Сгусток огня летит из вашей ладони к цели в пределах 120 фт. Совершите дальнобойную атаку заклинанием. При попадании цель получает 1d10 огненного урона. Горючие предметы, не несомые и не носимые, загораются.', 'Урон увеличивается на 1d10 на 5, 11 и 17 уровнях.', '["sorcerer","wizard"]', false),

('Электрический разряд', 0, 'evocation', '1 действие', '120 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Вы посылаете молнию к существу. Оно должно пройти спасбросок Ловкости СЛ Вашей магии или получить 1d8 урона молнией.', 'Урон увеличивается на 1d8 на 5, 11 и 17 уровнях.', '["sorcerer","wizard","artificer"]', false),

('Яд', 0, 'conjuration', '1 действие', '10 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Ядовитое облако окутывает существо в пределах 10 фт. Оно должно пройти спасбросок Телосложения СЛ Вашей магии или получить 1d12 ядовитого урона и стать отравленным до конца вашего следующего хода.', 'Урон увеличивается на 1d12 на 5, 11 и 17 уровнях.', '["druid","sorcerer","warlock","wizard","artificer"]', false),

('Фокусы', 0, 'transmutation', '1 действие', '10 фт', '{"v":false,"s":true,"m":null}', 'До 1 часа', false, false, 'Вы совершаете одну из следующих магических причуд: чувствуете ближайшую погоду на следующий час, зажигаете или гасите свечу/факел/маленький костёр, убираете грязь или делаете что-то аналогично незначительное.', NULL, '["bard","cleric","druid","sorcerer","warlock","wizard"]', false),

('Волшебный камень', 0, 'transmutation', '1 бонусное действие', '60 фт', '{"v":false,"s":true,"m":null}', '1 минута', false, false, 'До трёх обычных камней заряжаются магией. Существо может бросить заряженный камень: дальнобойная атака заклинанием, дальность 60 фт. При попадании 1d6 + ваш модификатор мудрости дроблящего урона.', NULL, '["druid","artificer","warlock"]', false),

('Руки мертвеца', 0, 'necromancy', '1 действие', '60 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Дух одного нежити, погибшей в 60 фт. от вас за последние 1 минуту, испускает замогильный крик. Все существа в 10 фт. от этой нежити должны пройти спасбросок Телосложения СЛ Вашей магии или получить 1d8 некротического урона.', 'Урон увеличивается на 1d8 на 5, 11 и 17 уровнях.', '["warlock","wizard"]', false),

('Кислотный всплеск', 0, 'conjuration', '1 действие', '60 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Пузырёк кислоты летит к одному или двум существам в пределах 60 фт. друг от друга. Цели должны пройти спасбросок Ловкости СЛ Вашей магии или получить 1d6 кислотного урона.', 'Урон увеличивается на 1d6 на 5, 11 и 17 уровнях.', '["sorcerer","wizard"]', false),

('Свет', 0, 'evocation', '1 действие', 'Касание', '{"v":true,"s":false,"m":"светлячок или немного фосфорного мха"}', '1 час', false, false, 'Вы касаетесь предмета размером не более 10 фт. Он начинает светиться ярким светом на 20 фт. и тусклым ещё на 20 фт. Это заклинание можно отменить действием. Если заклинание нацелено на существо — спасбросок Ловкости.', NULL, '["bard","cleric","sorcerer","wizard","artificer"]', false),

-- УРОВЕНЬ 1
('Исцеляющее слово', 1, 'evocation', '1 бонусное действие', '60 фт', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false, 'Существо на ваш выбор в пределах 60 фт. восстанавливает HP равное 1d4 + ваш модификатор заклинательной характеристики. Это заклинание не действует на нежить и конструктов.', 'При использовании ячейки 2 и выше: дополнительно 1d4 за каждый уровень выше 1-го.', '["bard","cleric","druid"]', false),

('Лечение ран', 1, 'evocation', '1 действие', 'Касание', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Существо, которого вы касаетесь, восстанавливает HP равное 1d8 + ваш модификатор заклинательной характеристики. Это заклинание не действует на нежить и конструктов.', 'При использовании ячейки 2 и выше: дополнительно 1d8 за каждый уровень выше 1-го.', '["bard","cleric","druid","paladin","ranger"]', false),

('Волшебная стрела', 1, 'evocation', '1 действие', '120 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Вы создаёте три светящихся стрелы силы. Каждая стрела поражает существо на ваш выбор в пределах 120 фт. Стрела наносит 1d4+1 урона силой. Стрелы летят одновременно и могут бить одну или несколько целей.', 'При использовании ячейки 2 и выше: одна дополнительная стрела за каждый уровень выше 1-го.', '["sorcerer","wizard"]', false),

('Щит', 1, 'abjuration', '1 реакция', 'На себя', '{"v":true,"s":true,"m":null}', '1 раунд', false, false, 'Невидимый барьер магической силы появляется, защищая вас. До начала вашего следующего хода вы получаете +5 к КД, в том числе против атаки, спровоцировавшей реакцию. Также вы не получаете урона от «Волшебной стрелы».', NULL, '["sorcerer","wizard"]', false),

('Усыпление', 1, 'enchantment', '1 действие', '90 фт', '{"v":true,"s":true,"m":"щепотка тонкого песка, лепестки розы или сверчок"}', '1 минута', false, false, 'Это заклинание погружает существ в магический сон. Бросьте 5d8: результат — максимальное количество HP существ, которых это заклинание может усыпить. Существа в пределах 20 фт., начиная с минимального HP.', 'При использовании ячейки 2 и выше: дополнительно 2d8 за каждый уровень выше 1-го.', '["bard","sorcerer","wizard"]', false),

('Волна грома', 1, 'evocation', '1 действие', 'На себя (15-футовый куб)', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Волна громовой силы охватывает куб 15 фт. от вас. Все существа в области должны пройти спасбросок Телосложения СЛ Вашей магии или получить 2d8 урона звуком и быть отброшенными на 10 фт.', 'При использовании ячейки 2 и выше: дополнительно 1d8 за каждый уровень выше 1-го.', '["bard","druid","sorcerer","wizard"]', false),

('Колдовской снаряд', 1, 'evocation', '1 действие', '90 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Горящий шар летит к целевому существу. Совершите дальнобойную атаку заклинанием. При попадании цель получает 2d10 огненного урона.', 'При использовании ячейки 2 и выше: дополнительно 1d10 за каждый уровень выше 1-го.', '["sorcerer","warlock","wizard"]', false),

('Обнаружение магии', 1, 'divination', '1 действие', 'На себя', '{"v":true,"s":true,"m":null}', 'Концентрация, до 10 минут', true, true, 'В течение действия заклинания вы чувствуете наличие магии в пределах 30 фт. Вы можете действием увидеть слабую ауру вокруг любого видимого магического существа или предмета в этой области и узнать его школу магии.', NULL, '["bard","cleric","druid","paladin","ranger","sorcerer","wizard","artificer"]', false),

('Длинный шаг', 1, 'transmutation', '1 действие', 'Касание', '{"v":false,"s":true,"m":null}', '1 час', false, false, 'Вы касаетесь существа. Его скорость увеличивается на 10 фт. на время действия заклинания.', 'При использовании ячейки 2 и выше: дополнительно одно существо за каждый уровень выше 1-го.', '["bard","druid","ranger","sorcerer","wizard","artificer"]', false),

('Доспехи мага', 1, 'abjuration', '1 действие', 'Касание', '{"v":true,"s":true,"m":"кусочек кожи"}', '8 часов', false, false, 'Вы касаетесь добровольного существа, не носящего доспеха. Его КД становится 13 + модификатор Ловкости. Заклинание заканчивается если существо надевает доспех или вы отменяете его.', NULL, '["sorcerer","wizard"]', false),

('Полиморф', 1, 'transmutation', '1 действие', '60 фт', '{"v":true,"s":true,"m":"гусеница"}', 'Концентрация, до 1 часа', true, false, 'Это заклинание превращает существо, которое вы видите в пределах 60 фт. Существо должно пройти спасбросок Мудрости СЛ Вашей магии. Вы трансформируете существо в нового зверя, выбранного вами.', NULL, '["bard","druid","sorcerer","wizard"]', false),

-- УРОВЕНЬ 2
('Огненный шар', 3, 'evocation', '1 действие', '150 фт', '{"v":true,"s":true,"m":"крошечный шарик из гуано летучей мыши и серы"}', 'Мгновенно', false, false, 'Яркий огонь вспыхивает сферой радиусом 20 фт. с выбранной вами точки в пределах дальности. Каждое существо в этой области должно пройти спасбросок Ловкости СЛ Вашей магии, получая 8d6 огненного урона при провале или половину при успехе.', 'При использовании ячейки 4 и выше: дополнительно 1d6 за каждый уровень выше 3-го.', '["sorcerer","wizard"]', false),

('Невидимость', 2, 'illusion', '1 действие', 'Касание', '{"v":true,"s":true,"m":"ресница, завёрнутая в жевательную резинку"}', 'Концентрация, до 1 часа', true, false, 'Существо, которого вы касаетесь, становится невидимым до конца действия заклинания. Всё, что несёт или носит это существо, также становится невидимым. Заклинание заканчивается для этого существа, если оно атакует или колдует.', 'При использовании ячейки 3 и выше: дополнительно одно существо за каждый уровень выше 2-го.', '["bard","sorcerer","warlock","wizard","artificer"]', false),

('Паутина', 2, 'conjuration', '1 действие', '60 фт', '{"v":true,"s":true,"m":"кусочек паутины"}', 'Концентрация, до 1 часа', true, false, 'Вы вызываете большую массу толстой, липкой паутины в кубе 20 фт. с выбранной точки. Паутина — сложная местность и слабо освещена. Существо, входящее в паутину, должно пройти спасбросок Ловкости СЛ Вашей магии или стать обездвиженным.', NULL, '["sorcerer","wizard"]', false),

('Удержание личности', 2, 'enchantment', '1 действие', '30 фт', '{"v":true,"s":true,"m":"небольшая прямая часть железа"}', 'Концентрация, до 1 минуты', true, false, 'Выберите гуманоида в пределах 30 фт. Оно должно пройти спасбросок Мудрости СЛ Вашей магии или стать парализованным на время действия.', 'При использовании ячейки 3 и выше: дополнительно одно существо за каждый уровень выше 2-го.', '["bard","cleric","sorcerer","warlock","wizard"]', false),

('Удар духа', 2, 'evocation', '1 бонусное действие', 'На себя', '{"v":true,"s":false,"m":null}', 'Концентрация, до 1 минуты', true, false, 'Следующий раз, когда вы попадаете по существу атакой оружием в течение действия, вы наносите дополнительно 3d6 психического урона. Когда заклинание заканчивается, оно исчезает после первого попадания.', 'При использовании ячейки 3 и выше: дополнительно 1d6 за каждый уровень выше 2-го.', '["paladin"]', false),

('Восстановление', 2, 'evocation', '1 действие', 'Касание', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Существо, которого вы касаетесь, восстанавливает HP равное 2d8 + ваш модификатор заклинательной характеристики.', 'При использовании ячейки 3 и выше: дополнительно 1d8 за каждый уровень выше 2-го.', '["bard","cleric","druid","paladin","ranger"]', false),

('Мистическая стрела', 2, 'abjuration', '1 реакция', 'На себя', '{"v":true,"s":true,"m":null}', '1 раунд', false, false, 'Вы реагируете на снаряд, летящий в вас. Ваша KД увеличивается на 2, включая атаку, вызвавшую реакцию.', NULL, '["wizard"]', false),

('Звёздный луч', 2, 'evocation', '1 действие', '60 фт', '{"v":true,"s":true,"m":null}', 'Концентрация, до 1 минуты', true, false, 'Яркий луч появляется из вашей указывающей руки к существу в пределах 60 фт. Совершите дальнобойную атаку заклинанием. При попадании цель получает 4d6 сияющего урона и должна пройти спасбросок Телосложения СЛ Вашей магии или стать ослеплённой.', 'При использовании ячейки 3 и выше: дополнительно 1d6 за каждый уровень выше 2-го.', '["cleric","sorcerer","wizard"]', false),

-- УРОВЕНЬ 3
('Контрзаклинание', 3, 'abjuration', '1 реакция', '60 фт', '{"v":false,"s":true,"m":null}', 'Мгновенно', false, false, 'Вы пытаетесь прервать существо в процессе накладывания заклинания. Если оно колдует заклинание 3-го уровня или ниже — оно не срабатывает. Если 4-го уровня или выше — вы бросаете проверку магии СЛ 10+уровень заклинания.', NULL, '["sorcerer","warlock","wizard"]', false),

('Снятие проклятия', 3, 'abjuration', '1 действие', 'Касание', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Вы касаетесь одного существа или предмета. Все проклятия на этом существе или предмете снимаются. Если предмет был проклятым магическим предметом — ваше заклинание разрывает настройку на него.', NULL, '["cleric","paladin","warlock","wizard"]', false),

('Дневной свет', 3, 'evocation', '1 действие', '60 фт', '{"v":true,"s":true,"m":null}', '1 час', false, false, 'Сфера света радиусом 60 фт. исходит от точки на ваш выбор. Сфера ярко освещает всё в пределах 60 фт. и тускло — ещё на 60 фт. Тьма, созданная заклинанием 3-го уровня и ниже, рассеивается.', NULL, '["cleric","druid","paladin","ranger","sorcerer"]', false),

('Ускорение', 3, 'transmutation', '1 действие', '30 фт', '{"v":true,"s":true,"m":"каплю патоки"}', 'Концентрация, до 1 минуты', true, false, 'Выберите существо в пределах 30 фт. До конца заклинания скорость цели удваивается, она получает +2 к КД, получает преимущество на спасброски Ловкости и дополнительное действие в каждый ход.', NULL, '["sorcerer","wizard","artificer"]', false),

('Стрела молнии', 3, 'transmutation', '1 бонусное действие', 'На себя', '{"v":true,"s":true,"m":null}', 'Концентрация, до 1 минуты', true, false, 'Следующий раз, когда вы совершаете атаку дальнобойным оружием в течение этого заклинания, цель атаки и все существа в 10 фт. от неё должны пройти спасбросок Ловкости СЛ Вашей магии. Урон: 4d8 молнии при провале, половину при успехе.', 'При использовании ячейки 4 и выше: дополнительно 1d8 за каждый уровень выше 3-го.', '["ranger"]', false),

('Призыв зверя', 3, 'conjuration', '1 действие', '90 фт', '{"v":true,"s":true,"m":"маленький фигурку животного"}', 'Концентрация, до 1 часа', true, false, 'Вы призываете зверяного духа, который принимает форму зверя на ваш выбор из списка. Дух появляется в свободном пространстве в 90 фт. от вас и действует на вашей инициативе. Он следует вашим командам.', 'При использовании ячейки 4 и выше: чудовище имеет доп. 10 HP за каждый уровень выше 3-го.', '["druid","ranger"]', false),

-- УРОВЕНЬ 4
('Страж веры', 4, 'conjuration', '1 действие', '30 фт', '{"v":true,"s":false,"m":null}', '8 часов', false, false, 'Огромный призрачный страж появляется и парит в незанятом пространстве на ваш выбор в пределах 30 фт. Страж занимает это пространство и невидим всем, кроме вас. Существо, впервые вошедшее в пространство 10 фт. от стража, получает 20 урона сиянием или некротикой. Страж имеет 60 HP.', NULL, '["cleric"]', false),

('Полиморф', 4, 'transmutation', '1 действие', '60 фт', '{"v":true,"s":true,"m":"гусеница"}', 'Концентрация, до 1 часа', true, false, 'Это заклинание превращает существо, которое вы можете видеть в пределах 60 фт., в новый облик. Несогласное существо должно пройти спасбросок Мудрости СЛ Вашей магии. Цель принимает форму зверя с КО не выше уровня существа.', NULL, '["bard","druid","sorcerer","wizard"]', false),

('Ледяной шторм', 4, 'evocation', '1 действие', '300 фт', '{"v":true,"s":true,"m":"щепотка пыли и несколько капель воды"}', 'Мгновенно', false, false, 'Ледяной дождь бьёт в цилиндре радиусом 20 фт. и высотой 40 фт. с выбранной точки. Каждое существо в области должно пройти спасбросок Ловкости СЛ Вашей магии, получая 2d8 дроблящего и 4d6 холодного урона при провале.', 'При использовании ячейки 5 и выше: дополнительно 1d8 дроблящего за каждый уровень.', '["druid","sorcerer","wizard"]', false),

('Смерть', 4, 'necromancy', '1 действие', '150 фт', '{"v":true,"s":true,"m":null}', 'Мгновенно', false, false, 'Чёрный луч смерти вырывается из вашего пальца. Существо в пределах 150 фт. должно пройти спасбросок Ловкости СЛ Вашей магии. При провале цель получает 8d4+40 некротического урона. Если это снижает HP гуманоида до 0 — он умирает.', 'При использовании ячейки 5 и выше: дополнительно 2d4 за каждый уровень.', '["sorcerer","warlock","wizard"]', false),

-- УРОВЕНЬ 5
('Оживление', 5, 'necromancy', '1 час', 'Касание', '{"v":true,"s":true,"m":"бриллиант стоимостью 300 зм"}', 'Мгновенно', false, false, 'Вы возвращаете к жизни мёртвое существо, которого касаетесь, если оно умерло не более 10 дней назад. Если душа существа желает вернуться и не находится в заточении, оно оживает с 1 HP. Существо получает 1 уровень истощения.', NULL, '["bard","cleric","druid","paladin"]', false),

('Конус холода', 5, 'evocation', '1 действие', 'На себя (конус 60 фт)', '{"v":true,"s":true,"m":"маленький кристалл или стеклянный конус"}', 'Мгновенно', false, false, 'Ледяной воздух вырывается из ваших рук конусом 60 фт. Каждое существо в этой области должно пройти спасбросок Телосложения СЛ Вашей магии, получая 8d8 холодного урона при провале или половину при успехе.', 'При использовании ячейки 6 и выше: дополнительно 1d8 за каждый уровень.', '["sorcerer","wizard"]', false),

('Стена силы', 5, 'evocation', '1 действие', '120 фт', '{"v":true,"s":true,"m":"щепотка порошка из чистого кварца"}', 'Концентрация, до 10 минут', true, false, 'Невидимая стена из силы появляется в точке на ваш выбор. Стена может быть горизонтальной, вертикальной или наклонной. Она непроницаема для физических объектов и заклинаний. Ничто не может пройти сквозь неё.', NULL, '["sorcerer","wizard"]', false),

('Небесный огонь', 5, 'evocation', '1 действие', '150 фт', '{"v":true,"s":true,"m":"огненный рубин стоимостью 50 зм"}', 'Концентрация, до 1 минуты', true, false, 'Колонна пламени вспыхивает в точке на ваш выбор. До конца заклинания любое существо, заканчивающее ход в зоне 10 фт. от этой точки, получает 4d10 огненного урона.', NULL, '["druid","sorcerer"]', false),

-- УРОВЕНЬ 6
('Цепная молния', 6, 'evocation', '1 действие', '150 фт', '{"v":true,"s":true,"m":"кусочек меди, стеклянный стержень, шёлк"}', 'Мгновенно', false, false, 'Вы создаёте молнию, прыгающую к цели, которую вы выбираете в пределах 150 фт. Она прыгает к 3 другим существам в 30 фт. от первоначальной цели. Каждое существо должно пройти спасбросок Ловкости СЛ Вашей магии. Урон: 10d8 молнией.', 'При использовании ячейки 7 и выше: одно дополнительное существо за каждый уровень.', '["sorcerer","wizard"]', false),

('Тюрьма разума', 6, 'illusion', '1 действие', '60 фт', '{"v":true,"s":false,"m":null}', 'Концентрация, до 1 минуты', true, false, 'Вы атакуете разум существа в 60 фт. Оно должно пройти спасбросок Интеллекта СЛ Вашей магии или стать заключённым в иллюзорный мир. Пока существо заключено — оно недееспособно.', NULL, '["bard","sorcerer","warlock","wizard"]', false),

-- УРОВЕНЬ 7
('Телепортация', 7, 'conjuration', '1 действие', '10 фт', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false, 'Вы и до 8 добровольных существ в пределах 10 фт. телепортируетесь к месту назначения на том же плане существования. Вы выбираете место назначения: знакомое место, постоянный телепортационный круг и т.д.', NULL, '["bard","sorcerer","wizard"]', false),

('Регенерация', 7, 'transmutation', '1 минута', 'Касание', '{"v":true,"s":true,"m":"моляр тролля и щепотка мха"}', '1 час', false, false, 'Вы касаетесь существа и стимулируете его естественные целительные способности. Цель восстанавливает 4d8+15 HP. На время действия заклинания цель восстанавливает 1 HP в начале каждого хода.', NULL, '["bard","cleric","druid"]', false),

-- УРОВЕНЬ 8
('Мощная рука', 8, 'evocation', '1 действие', '150 фт', '{"v":true,"s":true,"m":"яичная скорлупа и перчатка из змеиной кожи"}', 'Концентрация, до 1 минуты', true, false, 'Вы создаёте Большую руку светящейся силы в пределах 150 фт. Рука имеет КД 20 и HP равное вашему максимуму HP. Каждый ход вы можете командовать рукой. Она может атаковать (4d8+ваш мод), захватывать, отталкивать.', NULL, '["wizard"]', false),

-- УРОВЕНЬ 9
('Желание', 9, 'conjuration', '1 действие', 'На себя', '{"v":true,"s":false,"m":null}', 'Мгновенно', false, false, 'Это самое мощное заклинание смертных. Произнесите вслух своё желание, и реальность подчинится вам. Базовое применение — воспроизведение любого заклинания 8-го уровня или ниже без необходимости в компонентах. Вы также можете использовать его для достижения более грандиозных эффектов.', NULL, '["sorcerer","wizard"]', false),

('Предсказание', 9, 'divination', '1 минута', 'На себя', '{"v":true,"s":true,"m":"жертвоприношение стоимостью минимум 25 зм и орнаментированная шляпа"}', 'До 8 часов', false, false, 'Ваша магия и щедрый дар воплощают связь с богом или его слугами. Вы задаёте вопрос о конкретном действии, которое собираетесь предпринять в течение следующих 30 минут. Вы получаете предзнаменование — «благо», «беда» или «ничто».', NULL, '["cleric"]', false),

('Предотвращение смерти', 9, 'necromancy', '1 действие', '30 фт', '{"v":true,"s":true,"m":null}', 'Концентрация, до 1 минуты', true, false, 'Вы произносите слова силы, способные остановить смерть. Выберите до трёх существ в 30 фт. На время действия они не могут умереть из-за потери HP и их HP не может опуститься ниже 1.', NULL, '["cleric","paladin"]', false);
